import React, { useState, useCallback, useEffect, useMemo } from 'react';
import {
  Button,
  Select,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { TrialBalanceLineDto } from '../../../services/kt/models';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';

const labels = reportPageLabels.canDoiPhatSinh;
const TEST_ID = 'erp-can-doi-phat-sinh';
const PAGE_ID = 'kt-cdps';

const CanDoiPhatSinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [items, setItems] = useState<TrialBalanceLineDto[]>([]);
  const [loading, setLoading] = useState(false);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const handleLoad = useCallback(() => {
    setLoading(true);
    ktService.getTrialBalance({ month: Number(month), year: Number(year) })
      .then(res => setItems(res.items))
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  const hasData = items.length > 0;

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
        ),
      },
      {
        testId: `${TEST_ID}-reload-btn`,
        content: (
          <Button variant="primary" onClick={handleLoad} loading={loading} data-testid={`${TEST_ID}-reload-btn`}>
            {labels.reload}
          </Button>
        ),
      },
    ],
    [month, year, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: false,
      canPrint: hasData,
      onPrint: () => window.print(),
    }),
    [handleLoad, hasData],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th rowSpan={2}>{labels.colAccount}</th>
            <th rowSpan={2}>{labels.colAccountName}</th>
            <th colSpan={2} className={erp.colRight}>{labels.colOpening}</th>
            <th colSpan={2} className={erp.colRight}>{labels.colPeriod}</th>
            <th colSpan={2} className={erp.colRight}>{labels.colClosing}</th>
          </tr>
          <tr>
            <th className={erp.colRight}>{labels.colDebit}</th>
            <th className={erp.colRight}>{labels.colCredit}</th>
            <th className={erp.colRight}>{labels.colDebit}</th>
            <th className={erp.colRight}>{labels.colCredit}</th>
            <th className={erp.colRight}>{labels.colDebit}</th>
            <th className={erp.colRight}>{labels.colCredit}</th>
          </tr>
        </thead>
        <tbody>
          {items.map(r => (
            <tr key={r.accountCode}>
              <td><code>{r.accountCode}</code></td>
              <td>{r.accountName}</td>
              <td className={erp.colRight}>{formatVnd(r.openingDebit)}</td>
              <td className={erp.colRight}>{formatVnd(r.openingCredit)}</td>
              <td className={erp.colRight}>{formatVnd(r.periodDebit)}</td>
              <td className={erp.colRight}>{formatVnd(r.periodCredit)}</td>
              <td className={erp.colRight}>{formatVnd(r.closingDebit)}</td>
              <td className={erp.colRight}>{formatVnd(r.closingCredit)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-balance-scale-right',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.title}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default CanDoiPhatSinhPage;
